INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fca77e1e-fbe2-4aed-84d5-66732cf09029',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress Component Testing — Pure Functions and Custom Hooks Without renderHook$escape$,
  $escape$Cypress Component Testing doesn't ship `renderHook` — that's React Testing Library's API. For pure functions, `cy.wrap()` chains directly into Cypress assertions without mounting anything. For custom hooks, the idiomatic pattern is a minimal test-harness component: a tiny React component that calls your hook, exposes its output via `data-*` attributes, and lets `cy.get()` assert on the result.

This approach gives you more than RTL's `renderHook` — you can assert on DOM side effects, fire real events with `cy.type()` or `cy.click()`, and watch state updates propagate in the Cypress runner's visual preview.

For time-based hooks like `useDebounce`, mount a harness and use `cy.clock()` with `cy.tick()` instead of Jest's fake timers. No manual setup — `cy.clock()` intercepts `setTimeout` globally the moment it's called. Keep harness components co-located with the test file, not in shared fixtures, so hook signature changes surface as immediate local breakage rather than distant fixture drift.$escape$,
  $escape$function Harness({ value, delay }: { value: string; delay: number }) {
  const debounced = useDebouncedValue(value, delay)
  return <div data-testid="out">{debounced}</div>
}

it('debounces value', () => {
  cy.clock()
  cy.mount(<Harness value="hello" delay={300} />)
  cy.get('[data-testid=out]').should('have.text', '')
  cy.tick(300)
  cy.get('[data-testid=out]').should('have.text', 'hello')
})

// Pure function — no component needed
it('formats bytes', () => cy.wrap(formatBytes(1024)).should('eq', '1 KB'))$escape$,
  $escape$typescript$escape$,
