INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8ca27f86-5b55-419e-8a97-0db2073e0ef4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress E2E — Testing Critical Paths Without the Noise$escape$,
  $escape$Most Cypress suites die under maintenance load because teams test everything. E2E is expensive — reserve it for paths that break users: auth, onboarding, and your core value action.

For auth flows, skip the UI login on every test. Use cy.session() to cache the authenticated state across specs. Define a login command once, call it in beforeEach with a session key — Cypress replays the session from cache instead of hitting your login form on every run, cutting suite time dramatically.

For onboarding and core flows, use cy.intercept() to stub non-critical third-party calls (analytics, chat widgets) so flaky network conditions don't kill your signal. Keep assertions behavioral: cy.contains(), cy.location('pathname'), visible element checks — not implementation details like class names.

Structure specs by user journey, not by page. One spec file per critical path: auth.cy.ts, onboarding.cy.ts, core-action.cy.ts. Each should be independently runnable with no shared DOM state leaking between tests. Use cy.clearCookies() and cy.clearLocalStorage() in afterEach if session() isn't in play.$escape$,
  $escape$// cypress/support/commands.ts
Cypress.Commands.add('loginAsUser', (email: string, password: string) => {
  cy.session([email, password], () => {
    cy.visit('/login');
    cy.get('[data-cy=email]').type(email);
    cy.get('[data-cy=password]').type(password);
    cy.get('[data-cy=submit]').click();
    cy.location('pathname').should('eq', '/dashboard');
  });
});

// cypress/e2e/auth.cy.ts
beforeEach(() => {
  cy.loginAsUser('test@byteai.dev', 'Password123!');
});

it('redirects unauthenticated users to login', () => {
  cy.clearCookies();
  cy.visit('/dashboard');
  cy.location('pathname').should('eq', '/login');
});$escape$,
  $escape$typescript$escape$,
