INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1ee5eb68-80b3-44fc-997b-dafd979ad589',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress + MSW — Service Worker Mocking vs cy.intercept() and When to Pick Each$escape$,
  $escape$Cypress ships `cy.intercept()` for network stubbing, but MSW fills a different niche — particularly in Cypress Component Testing, where the mock lives at the service worker level and your component exercises the same fetch/axios code path as production.

`cy.intercept()` intercepts at the browser network proxy layer. It's ideal for E2E tests: coarse control over full request/response cycles, request aliasing with `cy.wait('@alias')`, and conditional stubbing mid-test. MSW is better for component tests where you want handler logic that mirrors your real API contract and can be reused outside Cypress (Storybook, unit tests).

Set up MSW once in `cypress/support/component.ts` via `setupWorker()`, then override per-test with `worker.use()`. Always call `worker.resetHandlers()` in `afterEach` to prevent handler leakage between tests.

**Mock when:** testing error states (500s, timeouts), CI without a live backend, or any component test where UI logic — not the API — is under test.

**Use real dependencies when:** running E2E critical paths, contract-verifying response shapes, or confirming integration between frontend and live backend. Stale MSW handlers return green tests against a broken API — the most dangerous false positive in frontend testing.$escape$,
  $escape$// cypress/support/component.ts
import { setupWorker } from 'msw/browser'
import { http, HttpResponse } from 'msw'
import { handlers } from '../../src/mocks/handlers'

export const worker = setupWorker(...handlers)
beforeEach(() => worker.start({ onUnhandledRequest: 'bypass' }))
afterEach(() => worker.resetHandlers())

// PostFeed.cy.tsx
it('shows error banner on 500', () => {
  worker.use(
    http.get('/api/posts', () => HttpResponse.json({}, { status: 500 }))
  )
  cy.mount(<PostFeed />)
  cy.get('[data-cy=error-banner]').should('be.visible')
})$escape$,
  $escape$typescript$escape$,
