INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd74d0f05-870f-4d70-8b10-70ec7a43070a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress Visual Regression — Chromatic for Components, Screenshot Diffing for Flows$escape$,
  $escape$Cypress doesn't ship visual diffing natively — `cy.screenshot()` captures, but `@simonsmith/cypress-image-snapshot` (wrapping pixelmatch) handles the comparison. Register `addMatchImageSnapshotCommand()` in `cypress/support/commands.ts`, then call `cy.matchImageSnapshot('baseline-name')` after your UI has fully settled.

In CI, the first run seeds baselines under `cypress/snapshots/`. Subsequent runs diff against them and fail if pixel delta exceeds `failureThreshold` (default 0.01 — 1%). Gate updates behind `CYPRESS_updateSnapshots=true` so baselines only change on deliberate commits, never on flaky reruns.

Chromatic handles the other half: it runs your Storybook stories headlessly and ships pixel diffs to a cloud dashboard, catching component-level regressions without browser automation. The division of labor matters — Chromatic owns isolated component diffing; Cypress owns interaction-driven page state stories can't replicate. A multi-step wizard, a toast triggered post-API call, a skeleton-to-data transition — these belong to Cypress.

In GitHub Actions, run both in the same job: `chromatic --exit-zero-on-changes` first as a non-blocking review gate, then `cypress run` as your hard failure gate.$escape$,
  $escape$// cypress/support/commands.ts
import { addMatchImageSnapshotCommand } from '@simonsmith/cypress-image-snapshot/command';

addMatchImageSnapshotCommand({
  failureThreshold: 0.02,
  failureThresholdType: 'percent',
  customSnapshotsDir: 'cypress/snapshots',
});

// cypress/e2e/dashboard.cy.ts
it('matches dashboard baseline after data loads', () => {
  cy.visit('/dashboard');
  cy.get('[data-testid="chart"]').should('be.visible');
  cy.matchImageSnapshot('dashboard-chart');
});$escape$,
