INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '016d5539-c723-4ad7-85b4-e17636c08def',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress CI Integration — Parallelizing Tests, Caching, and Fail-Fast Strategies$escape$,
  $escape$Cypress Cloud's `--parallel` flag splits your spec files across CI machines using historical run data to balance load. Each machine runs `cypress run --record --parallel --ci-build-id $CI_BUILD_ID`, and Cypress Cloud orchestrates spec distribution dynamically — no static sharding needed.

For caching, store `~/.cache/Cypress` (the binary) and `node_modules` separately. The binary rarely changes, so its cache hit rate approaches 100%. On GitHub Actions, key the `node_modules` cache on `hashFiles('**/package-lock.json')` and the Cypress binary cache on the Cypress version from `package.json`.

Fail-fast isn't built into Cypress Cloud natively, but you can approximate it: use `--exit-code-on-failure` in your CI step combined with `--bail` in `cypress.config.ts` (`bail: 1` stops the run after the first failing spec on that machine). For true cross-machine fail-fast, use Cypress Cloud's cancel-on-failure feature, which aborts all parallel runners when any machine reports a failure — configurable under project settings.$escape$,
  $escape$# .github/workflows/cypress.yml
jobs:
  cypress-run:
    runs-on: ubuntu-latest
    strategy:
      matrix:
        containers: [1, 2, 3]
    steps:
      - uses: actions/cache@v4
        with:
          path: ~/.cache/Cypress
          key: cypress-binary-${{ hashFiles('**/package.json') }}
      - uses: actions/cache@v4
        with:
          path: node_modules
          key: node-modules-${{ hashFiles('**/package-lock.json') }}
      - run: npx cypress run --record --parallel --ci-build-id ${{ github.run_id }}$escape$,
  $escape$bash$escape$,
