INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a3e0bc6f-b4d1-4c70-a655-81ac48ec4d20',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress cy.intercept + Component Testing — Wire Up Real Network Behavior$escape$,
  $escape$Cypress Component Testing (CT) runs your components in isolation, but real apps talk to APIs. Unlike E2E mode, CT doesn't spin up a full server — so cy.intercept() becomes your only network layer. Mount the component, intercept the request before it fires, and assert on both the stub response and the resulting DOM.

cy.intercept() in CT works identically to E2E: it pattern-matches by method/URL and can return a fixture, a static body, or a routeHandler function that lets you inspect the actual request. Use cy.wait('@alias') to pause the test until the intercepted request completes — this eliminates flaky setTimeout hacks.

A critical CT-specific gotcha: if your component fires a request on mount, declare cy.intercept() before cy.mount(), otherwise the request races past the stub. Also, CT shares no cookies or session state with E2E specs — stub auth headers explicitly inside the routeHandler or via cy.intercept's headers option. Combine with cy.fixture() to keep payloads maintainable across multiple component specs.$escape$,
  $escape$import { mount } from 'cypress/react';
import UserCard from './UserCard';

it('renders user data from API', () => {
  cy.intercept('GET', '/api/users/42', {
    statusCode: 200,
    fixture: 'user.json',
    headers: { Authorization: 'Bearer test-token' },
  }).as('getUser');

  mount(<UserCard userId={42} />);

  cy.wait('@getUser');

  cy.get('[data-cy="user-name"]').should('contain', 'Jane Doe');
  cy.get('[data-cy="user-role"]').should('contain', 'Engineer');
});$escape$,
  $escape$typescript$escape$,
