INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '36955291-fe1d-4874-b4e8-79a10a396827',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress + Storybook — Story-Driven Component Testing with composeStories$escape$,
  $escape$Cypress Component Testing integrates directly with Storybook via `composeStories` from `@storybook/react`. Instead of duplicating setup — mocks, decorators, args — across both stories and component tests, you import stories as-is and mount them with `cy.mount()`. The story's args, decorators, and global parameters all compose automatically.

`composeStories` resolves each named export against your global Storybook config, giving you a fully hydrated React component. A `Loading` story that wraps a context provider and pre-sets `isLoading: true` doesn't need to be re-described in your test — mount it directly.

For assertions, Cypress outperforms Storybook's built-in `play` function: use `cy.intercept()` for network-level validation, `cy.get('@spy').should('have.been.calledWith', ...)` for action args wired as stubs, and `cy.wait('@alias')` for async state transitions. No Storybook server is required — `cypress run --component` bundles stories through Cypress's own Vite dev server.

This pattern keeps stories as the single source of truth for component states, eliminates test setup duplication, and gives you real browser assertions that `play` functions simply can't match.$escape$,
  $escape$import { composeStories } from '@storybook/react';
import * as stories from '../../src/components/Button.stories';

const { Primary, Disabled, Loading } = composeStories(stories);

describe('Button — story-driven', () => {
  it('fires onClick from Primary story args', () => {
    cy.mount(<Primary />);
    cy.get('button').should('not.be.disabled').click();
    cy.get('@onClick').should('have.been.calledOnce');
  });

  it('blocks interaction in Disabled story', () => {
    cy.mount(<Disabled />);
    cy.get('button').should('be.disabled');
  });

  it('shows spinner during async op in Loading story', () => {
    cy.mount(<Loading />);
    cy.get('[data-cy=spinner]').should('be.visible');
  });
});$escape$,
